namespace {
static inline uint32_t CeilDiv(uint64_t a, uint64_t b) {
    return static_cast<uint32_t>((a + b - 1) / b);
}
static inline int64_t GetDim(const gert::Shape &s, int idx) {
    return s.GetDim(static_cast<uint32_t>(idx));
}
