#include <torch/library.h>
#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"

at::Tensor conv3d_min_softmax_impl_npu(const at::Tensor& x,
                                       const at::Tensor& weight,
                                       const at::Tensor& bias,
                                       c10::optional<int64_t> stride_d = 1,
                                       c10::optional<int64_t> stride_h = 1,
                                       c10::optional<int64_t> stride_w = 1,
                                       c10::optional<int64_t> pad_d = 0,
                                       c10::optional<int64_t> pad_h = 0,
                                       c10::optional<int64_t> pad_w = 0,
                                       c10::optional<int64_t> dilation_d = 1,
                                       c10::optional<int64_t> dilation_h = 1,
                                       c10::optional<int64_t> dilation_w = 1,
                                       c10::optional<int64_t> groups = 1) {
    // Infer output shape on host for allocation
    auto x_sizes = x.sizes();
    auto w_sizes = weight.sizes();
    int64_t N = x_sizes[0];
    int64_t Cin = x_sizes[1];
    int64_t Din = x_sizes[2];
    int64_t Hin = x_sizes[3];
    int64_t Win = x_sizes[4];

    int64_t Cout = w_sizes[0];
    int64_t Kd   = w_sizes[2];
    int64_t Kh   = w_sizes[3];
    int64_t Kw   = w_sizes[4];

    int64_t sD = stride_d.value_or(1);
    int64_t sH = stride_h.value_or(1);
    int64_t sW = stride_w.value_or(1);
    int64_t pD = pad_d.value_or(0);
